[[0, 31, 'm\'\nGREEN=\'033[0;32m\'\nYELLOW=\'033[1;33m\'\nNC=\'033[0m\' # No Color\n\n# Function to print colored output\nprint_status() {\n    echo -e "${GREEN}$1${NC}"\n}\n\nprint_warning() {\n    echo -e "${YELLOW}$1${NC}"\n}\n\nprint_error() {\n    echo -e "${RED}$1${NC}"\n}\n\n# Function to check if a command exists\ncommand_exists() {\n    command -v "$1" >/dev/null 2>&1\n}\n\n# Function to check if Flutter is installed\ncheck_flutter() {\n    if ! command_exists flutter; then\n        print_error "Flutter is not installed or not in PATH"\n        echo "Please install Flutter by following instructions at: https://flutter.dev/docs/get-started/install"\n        exit 1\n    fi\n    print_status "Flutter is installed"\n}\n\n# Function to check project structure\ncheck_project_structure() {\n    if [ ! -d "ezybiz'], ['f "ezybiz/pubspec.yaml'], ['d "callconcierge'], ['f "callconcierge/pubspec.yaml'], {'$app" != "ezybiz" ] && [ "$app" != "callconcierge" ]; then\n        print_error': 'nvalid app: $app', 'Valid apps are: ezybiz, callconcierge': 'xit 1\n    fi'}, {'Running flutter pub get for $app..."\n    cd "$app': 'exit 1\n    flutter pub get\n    cd ..'}, {'Checking for connected Android devices..."\n    local devices=$(flutter devices | grep -i android)\n    \n    if [ -z "$devices" ]; then\n        print_warning': 'o Android devices found. Make sure you have:', '1. Enabled Developer Options and USB Debugging on your device"\n        echo "2. Connected your device via USB"\n        echo "3. Or started an Android emulator"\n        read -p': 'o you want to continue anyway? (y/N):', 'Found Android devices:"\n        echo "$devices"\n    fi\n    \n    print_status "Running $app on Android..."\n    cd "$app': 'exit 1\n    flutter run -d android\n    cd ..'}, {'$OSTYPE" != "darwin"* ]]; then\n        print_error': 'OS development requires macOS. You are running: $OSTYPE', 'Checking for connected iOS devices..."\n    local devices=$(flutter devices | grep -i ios)\n    \n    if [ -z "$devices" ]; then\n        print_warning': 'o iOS devices found. Make sure you have:', '1. Connected your iPhone via USB"\n        echo "2. Or started an iOS simulator"\n        echo "3. Set up Xcode and signing properly"\n        read -p': 'o you want to continue anyway? (y/N):', 'Found iOS devices:"\n        echo "$devices"\n    fi\n    \n    print_status "Running $app on iOS..."\n    cd "$app': 'exit 1\n    flutter run -d ios\n    cd ..'}, {'$android_devices" ] && [ -z "$ios_devices" ]; then\n        echo "android"\n    elif [ -z "$android_devices" ] && [ -n "$ios_devices" ]; then\n        echo "ios"\n    else\n        # If both or neither are found, default to android\n        echo "android': 'i'}, {'Usage: $0 [APP] [PLATFORM]"\n    echo "Run the Flutter app on Android or iOS."\n    echo\n    echo': 'pps:', 'ezybiz          Run EzyBiz app"\n    echo "callconcierge   Run CallConcierge app"\n    echo\n    echo': 'latforms:', 'android    Run on Android"\n    echo "ios        Run on iOS (macOS only)"\n    echo\n    echo "If no platform is specified, the script will attempt to detect connected devices."\n    echo\n    echo': 'xamples:'}, 'Starting Flutter app runner"\n\n# Check prerequisites\ncheck_flutter\ncheck_project_structure\n\n# Parse command line arguments\nif [ $# -eq 0 ]; then\n    show_help\n    exit 1\nfi\n\nAPP=$1\nvalidate_app "$APP"\n\nPLATFORM=$2\nif [ -z "$PLATFORM" ]; then\n    PLATFORM=$(detect_platform)\n    print_status', 'platform', '$APP"\n\n# Run the app on the specified platform\ncase "$PLATFORM" in\n    android)\n        run_android "$APP"\n        ;;\n    ios)\n        run_ios "$APP"\n        ;;\n    *)\n        print_error', 'platform', 'Valid platforms are: android, ios', 1, 'esac']